  .filter((l) => l.route)
  .map((l) => `${Object.keys(l.route.methods)[0].toUpperCase()} ${l.route.path}`);

mkdirSync("dist", { recursive: true });
writeFileSync(
  "dist/build-manifest.json",
  JSON.stringify({ built: new Date().toISOString(), routes }, null, 2)
);
